CLUSTER_PROVIDER_ROUTE_ROW_IDS = frozenset(
    set(CLUSTER_PRIVATE_PUBLIC_REFUSAL_ROW_EVIDENCE)
    | set(SBSFC025RY_CLUSTER_PRIVATE_PUBLIC_REFUSAL_ROW_EVIDENCE)
    | set(CLUSTER_PROFILE_GATE_PUBLIC_REFUSAL_ROW_EVIDENCE)
    | set(SBSFC025RZ_CLUSTER_SCOPE_PUBLIC_REFUSAL_ROW_EVIDENCE)
)


def cluster_provider_route_operation_id(canonical_name: str) -> str:
    return f"cluster.surface.{canonical_name.lower()}"


def cluster_provider_route_manifest_row(
    surface: dict[str, str],
    ledger_row: dict[str, str] | None,
) -> dict[str, str]:
    surface_id = surface["surface_id"]
    canonical_name = surface["canonical_name"]
    if surface["cluster_scope"] != "cluster_private":
        fail(f"{surface_id} cluster-provider route evidence requires cluster_private scope")
    if surface["status"] not in {"cluster_private", "native_now"}:
        fail(f"{surface_id} cluster-provider route evidence requires cluster_private or native_now status")
    if ledger_row is None:
        fail(f"{surface_id} cluster-provider route evidence requires strict ledger row")
    if ledger_row.get("current_state") != "exact_refusal_passed":
        fail(f"{surface_id} cluster-provider route evidence requires exact_refusal_passed strict ledger state")

    is_b015 = surface_id in CLUSTER_PROVIDER_ROUTE_B015_IDS
    ctest = (
        "sbsql_sblr_final_cleanup_b015_cluster_provider_route_conformance"
        if is_b015
        else "sbsql_sblr_final_cleanup_b016_cluster_provider_evidence_conformance"
    )
    implementation_refs = [
        "provider_boundary_route_evidence",
        f"surface_id={surface_id}",
        f"canonical_name={canonical_name}",
    ]
    if not is_b015:
        implementation_refs.append(f"operation_id={cluster_provider_route_operation_id(canonical_name)}")
    implementation_refs.extend(
        [
            "project/src/cluster_provider/cluster_provider.hpp",
            "project/src/cluster_provider/no_cluster_provider.cpp",
            "project/src/cluster_provider_stub/stub_cluster_provider.cpp",
            "project/src/engine/sblr/sblr_dispatch.cpp#cluster_provider_boundary",
            "project/src/server/sblr_admission.cpp#cluster_private_family_admission",
            "SBLR.CLUSTER.HANDSHAKE.STUB_COMPILE_LINK_ONLY",
            "no_direct_open_core_private_cluster_executor_dispatch",
            "private_cluster_execution=false",
        ]
    )
    return {
        "final_state": "cluster_provider_route_passed",
        "ctest_label": f"{ctest};sbsql_cluster_provider_split;sbsql_parser_worker;sbsql_e2e_passed",
        "fixture_path": "project/tests/sbsql_parser_worker/sbsql_sblr_final_cleanup_b015_cluster_provider_route_conformance.cpp",
        "implementation_refs": ";".join(implementation_refs),
        "diagnostic_proof": (
            "SBLR.CLUSTER.SUPPORT_NOT_ENABLED;SBLR.CLUSTER.STUB_RESPONSE;"
            "SBLR.CLUSTER.HANDSHAKE.STUB_COMPILE_LINK_ONLY;"
            "canonical_message_vector_set;no_row_detail_leak;no_private_cluster_execution"
        ),
        "result_proof": (
            f"ctest:{ctest};surface_id={surface_id};canonical_name={canonical_name};"
            "default_open_core_build_no_cluster_provider_returns_SBLR.CLUSTER.SUPPORT_NOT_ENABLED;"
            "cluster_enabled_stub_build_returns_cluster.provider.stub.v1_and_SBLR.CLUSTER.STUB_RESPONSE;"
            "SBLR.CLUSTER.HANDSHAKE.STUB_COMPILE_LINK_ONLY;"
            "request_lifecycle_routed_through_cluster_provider_boundary"
        ),
        "evidence_collected_utc": "static_existing_ctest_evidence",
        "promoter_slice": (
            "static_b015_cluster_provider_route_evidence"
            if is_b015
            else "static_b016_cluster_provider_route_evidence"
        ),
        "notes": (
            f"Bounded provider-boundary evidence for {surface_id}/{canonical_name}. "
            "Default/open-core builds route through the no-cluster provider and return "
            "SBLR.CLUSTER.SUPPORT_NOT_ENABLED without private cluster execution or stub dispatch. "
            "Cluster-enabled stub builds route through the separate cluster provider target and return "
            "cluster.provider.stub.v1 with SBLR.CLUSTER.STUB_RESPONSE. The evidence remains structural "
            "and provider-boundary only: no private cluster implementation, parser-side SQL execution, "
            "parser storage/finality, reference execution, transaction finality claim, or WAL/recovery "
            "authority is claimed."
        ),
    }


def bridge_command_surface_manifest_row(
    surface: dict[str, str],
    ledger_row: dict[str, str] | None,
) -> dict[str, str]:
    surface_id = surface["surface_id"]
    bridge = BRIDGE_COMMAND_BY_SURFACE_ID[surface_id]
    if surface["canonical_name"] != bridge.canonical_name:
        fail(
            f"{surface_id} bridge command manifest override stale: "
            f"expected canonical_name={bridge.canonical_name} observed={surface['canonical_name']}"
        )
    if surface["status"] != "native_now":
        fail(f"{surface_id} bridge command manifest override requires native_now status")
    if surface["cluster_scope"] != bridge.cluster_scope:
        fail(f"{surface_id} bridge command manifest override cluster_scope drift")
    if ledger_row is None:
        fail(f"{surface_id} bridge command manifest override requires strict ledger row")

    common_refs = [
        f"operation_id={bridge.operation_id}",
        f"opcode={bridge.opcode}",
        "operation_family=sblr.bridge.operation.v3",
        f"sql={bridge.sql}",
        f"udr_operation={bridge.effective_udr_operation}",
        f"requires_transaction_context={str(bridge.requires_transaction_context).lower()}",
        "bridge_abi=sb_universal_bridge_v1",
        "generated_registry_surface_id_asserted",
        "server_admission_admitted",
        "trusted_parser_support_udr_route",
        "authority.parser.no_sql_text_execution",
        "MGA_per_database_transaction_authority_preserved",
        "secret_refs_only",
    ]
    if bridge.udr_request_suffix:
        common_refs.append(f"udr_request_suffix={bridge.udr_request_suffix}")

    if bridge.cluster_route:
        if ledger_row.get("current_state") != "exact_refusal_passed":
            fail(f"{surface_id} bridge cluster manifest override requires exact_refusal_passed strict ledger state")
        implementation_refs = common_refs + [
            "provider_boundary_route_evidence",
            "cluster_provider_gate=compile_time",
            "SBLR.CLUSTER.SUPPORT_NOT_ENABLED",
            "SBLR.CLUSTER.STUB_RESPONSE",
            "SBLR.CLUSTER.HANDSHAKE.STUB_COMPILE_LINK_ONLY",
            "request_lifecycle_routed_through_cluster_provider_boundary",
            "UDR.BRIDGE.UNSUPPORTED",
            "UDR.BRIDGE.UNLICENSED",
            "private_cluster_execution=false",
        ]
        return {
            "final_state": "cluster_provider_route_passed",
            "ctest_label": f"{BRIDGE_CTEST};sbsql_cluster_provider_split;sbsql_parser_worker;sbsql_e2e_passed",
            "fixture_path": BRIDGE_TEST_SOURCE,
            "implementation_refs": ";".join(implementation_refs),
            "diagnostic_proof": (
                "canonical_message_vector_set;SBLR.CLUSTER.SUPPORT_NOT_ENABLED;"
                "SBLR.CLUSTER.STUB_RESPONSE;SBLR.CLUSTER.HANDSHAKE.STUB_COMPILE_LINK_ONLY;UDR.BRIDGE.UNSUPPORTED;"
                "UDR.BRIDGE.UNLICENSED;provider_boundary_route_evidence;"
                "private_cluster_execution=false"
            ),
            "result_proof": (
                f"ctest:{BRIDGE_CTEST};surface_id={surface_id};sql_fixture={bridge.sql};"
                "request_lifecycle_routed_through_cluster_provider_boundary;"
                "default_public_build_returns_UDR.BRIDGE.UNSUPPORTED;"
                "cluster_admitted_stub_returns_UDR.BRIDGE.UNLICENSED;SBLR.CLUSTER.STUB_RESPONSE;"
                "private_cluster_execution=false"
            ),
            "evidence_collected_utc": "static_existing_ctest_evidence",
            "promoter_slice": "SBSQL-BRIDGE-COMMAND-SURFACE-FULL-TRACKING",
            "notes": "Bridge cluster route command is tracked as a cluster-provider boundary proof, not public cluster execution. The route reaches SBLR bridge validation and trusted UDR dispatch, then fail-closes unsupported when cluster routing is disabled and unlicensed through the cluster stub when admitted. No private cluster implementation, distributed query, parser-side execution/finality, reference execution, WAL/recovery authority, or transaction finality change is claimed.",
        }

    if ledger_row.get("current_state") != "e2e_passed":
        fail(f"{surface_id} bridge command manifest override requires e2e_passed strict ledger state")
    expected_refusal = bridge.expected_refusal_code or "none"
    implementation_refs = common_refs + [
        f"expected_refusal_code={expected_refusal}",
        "private_cluster_execution=false",
    ]
    diagnostic = "canonical_message_vector_set;SBLR.ENVELOPE.*;SBLR.OPCODE.*"
    if bridge.expected_refusal_code:
        diagnostic = f"{diagnostic};{bridge.expected_refusal_code};policy_denial_exact_refusal_contract"
    return {
        "final_state": "e2e_passed",
        "ctest_label": f"sbsql_surface_to_sblr_full_implementation_closure;sbsql_parser_worker;{BRIDGE_CTEST};trusted_udr_bridge_gate;sbsql_e2e_passed",
        "fixture_path": BRIDGE_TEST_SOURCE,
        "implementation_refs": ";".join(implementation_refs),
        "diagnostic_proof": diagnostic,
        "result_proof": (
            f"ctest:{BRIDGE_CTEST};surface_id={surface_id};sql_fixture={bridge.sql};"
            f"operation_id={bridge.operation_id};opcode={bridge.opcode};"
            f"udr_operation={bridge.effective_udr_operation};expected_refusal_code={expected_refusal};"
            "parser_bound=true;verifier_admitted=true;server_admission_admitted=true;"
            "trusted_udr_bridge_dispatch=true;contains_sql_text=false"
        ),
        "evidence_collected_utc": "static_existing_ctest_evidence",
        "promoter_slice": "SBSQL-BRIDGE-COMMAND-SURFACE-FULL-TRACKING",
        "notes": "Bridge command surface is final row evidence for the universal bridge ABI route. The CTest covers parse, AST classification, bind, SBLR lowering, server admission, opcode registry lookup, trusted parser-support UDR dispatch, logical stream/CDC/proxy/cutover routing, and physical page-copy sandbox denial. Parser does not execute SQL text, own transaction finality, expose raw secrets, or replace MGA authority.",
    }


