def _sbsfc039_evidence(function_id: str, proof: str) -> dict[str, str]:
    name = function_id.rsplit(".", 1)[-1]
    return {
        "function_id": function_id,
        "sblr_binding": f"sblr.expr.xml_{name}.v3",
        "engine_entrypoint": f"xml_{name}",
        "proof": proof,
    }


