def sbsfc015_window_runtime_entrypoint(row: dict[str, str]) -> str:
    refs = row.get("oracle_authority_ref", "").split(";")
    if len(refs) != 2 or "#" not in refs[1]:
        fail(f"SBSFC_015_AGGREGATE_WINDOW_FIXTURES {row.get('surface_id', '')} window oracle_authority_ref drift")
    return refs[1].split("#", 1)[1]


